import{_ as l,o as e,c as r,a2 as a}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/8103_瀚荃/20260425/G11_前十大客戶與供應商穩定度_投資研究員.md","filePath":"審計報告庫/經營審計/8103_瀚荃/20260425/G11_前十大客戶與供應商穩定度_投資研究員.md"}'),i={name:"審計報告庫/經營審計/8103_瀚荃/20260425/G11_前十大客戶與供應商穩定度_投資研究員.md"};function n(o,t,s,d,g,h){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="g11-前十大客戶與供應商穩定度-投資研究員-審計報告" tabindex="-1">G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告 <a class="header-anchor" href="#g11-前十大客戶與供應商穩定度-投資研究員-審計報告" aria-label="Permalink to &quot;G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>近三年中，前十大客戶與供應商變動情形為何？客戶集中度風險是否正在惡化？</p><p><strong>目標公司</strong>：瀚荃 (8103) — 連接器與線纜組件製造商 <strong>審計日期</strong>：2026-04-25 <strong>資料時效</strong>：截至 2026 年第一季最新公開數據</p><hr><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>前十大客戶累計佔比約40-45%，Top 1僅8%，集中度「中等偏低」持續下降，且供應商原物料分散採購無單一依賴。客戶群從消費電子轉向AI伺服器與光電，名單穩定度高，集中度風險未惡化。</p><hr><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">評級維度</th><th style="text-align:center;">評分</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;">客戶集中度</td><td style="text-align:center;">A</td><td style="text-align:left;">Top 1 客戶約 8%，Top 2 各約 8%，無任一客戶 &gt; 15%</td></tr><tr><td style="text-align:left;">供應商穩定性</td><td style="text-align:center;">A</td><td style="text-align:left;">原物料分散採購，無單一依賴</td></tr><tr><td style="text-align:left;">名單穩定性</td><td style="text-align:center;">A</td><td style="text-align:left;">電源大廠合作超過 5 年，三星核心供應商 2024 年新加入</td></tr><tr><td style="text-align:left;">掉單緩衝能力</td><td style="text-align:center;">A</td><td style="text-align:left;">任一大客戶流失對營收影響 &lt; 10%</td></tr><tr><td style="text-align:left;"><strong>綜合評級</strong></td><td style="text-align:center;"><strong>A</strong></td><td style="text-align:left;"><strong>客戶結構健康，集中度風險可控</strong></td></tr></tbody></table><hr><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>一、客戶集中度三年變化：</strong> 瀚荃從NB/消費電子轉向AI伺服器。2023年伺服器約22%（AI僅6.5%）；2024年伺服器躍升至34%（AI 8%），光電受惠三星訂單升至10%；2025年伺服器達37%（AI Power跳升至18%），光電升至13.8%；2026 Q1 AI Power攀至21%。前十大客戶佔比從45-50%降至40-45%，客戶群擴大稀釋集中度。</p><p><strong>二、客戶名單穩定度：</strong> 電源大廠A、B合作超5年，共同開發AI電源規格；三星2024年成核心供應商（僅20間）；CSP供應鏈（AWS/Google）2025-2026年新打入，認證12-18個月構成高切換成本。名單持續新增Tier 1客戶，無異常消失。</p><p><strong>三、掉單壓力測試（Top 1客戶8%全失）：</strong> 營收影響2.68億，EPS影響約0.3-0.4元（降至約3.6元），仍高於2023年2.76元，衝擊可控。</p><p><strong>四、供應鏈韌性：</strong> 原物料分散採購無依賴；七座生產基地提供產能彈性；2025年啟動中國五減三產線精實，3-5年非中國產能目標40%。</p><hr><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="「大樹好乘涼」還是「孤注一擲」" tabindex="-1">「大樹好乘涼」還是「孤注一擲」？ <a class="header-anchor" href="#「大樹好乘涼」還是「孤注一擲」" aria-label="Permalink to &quot;「大樹好乘涼」還是「孤注一擲」？&quot;">​</a></h3><p>瀚荃的客戶結構屬於典型的「分散式大樹」——不是靠單一大客戶吃飯，而是手握多個 Tier 1 客戶：</p><ol><li><strong>三星核心供應商資格</strong>：僅 20 間，代表最高等級認證，形成強大的品牌背書效應</li><li><strong>電源大廠 A、B</strong>：各約 8%，總計 16%，是穩定現金流的基石</li><li><strong>CSP 供應鏈（AWS/Google）</strong>：2026 年新打入，ASIC 平台訂單將成為下一波成長動能</li><li><strong>ODM 合作夥伴</strong>：提供更廣泛的業務觸角</li></ol><h3 id="🟢-正面亮點" tabindex="-1">🟢 正面亮點 <a class="header-anchor" href="#🟢-正面亮點" aria-label="Permalink to &quot;🟢 正面亮點&quot;">​</a></h3><ul><li>客戶從消費電子成功轉型至 AI 伺服器/網通，客戶層級全面升級</li><li>最大客戶佔比僅 8%，極度分散</li><li>電源連接器領域競爭對手極少（僅一家未上市櫃台廠），訂單掌握度高</li><li>2025 年全年營收創 33.55 億新高，EPS 3.96 元（年增 23%）</li><li>2026 Q1 營收年增 15.9%，淡季不淡</li></ul><h3 id="🟡-潛在風險" tabindex="-1">🟡 潛在風險 <a class="header-anchor" href="#🟡-潛在風險" aria-label="Permalink to &quot;🟡 潛在風險&quot;">​</a></h3><ul><li>AI 需求短期波動可能影響 CSP 客戶拉貨節奏</li><li>筆電業務在中國在地化供應鏈競爭下持續衰退（2025 Q4 筆電季減 15%，年減 6%）</li><li>東南亞新廠初期良率與管理成本仍需觀察</li></ul><hr><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ol><li><p><strong>FinMind — 月營收數據 (revenue 8103 2023-01-01 2026-04-25)</strong></p><ul><li>2023 年營收：29.77 億</li><li>2024 年營收：31.18 億（YoY +4.7%）</li><li>2025 年營收：33.35 億（YoY +7.0%）</li><li>2026 Q1 營收：9.10 億（YoY +15.9%）</li></ul></li><li><p><strong>FinMind — 綜合損益表 (finance 8103 2023-01-01 2026-04-25)</strong></p><ul><li>2023 毛利率 34.1% → 2024 年 34.8% → 2025 年 37.4%（持續改善）</li><li>2023 營益率 10.0% → 2024 年 11.4% → 2025 年 13.4%</li></ul></li><li><p><strong>優分析產業報告 (2025-04-09)</strong>：瀚荃 AI 伺服器 PSU 板上連接器競爭對手僅一家未上市櫃台廠，訂單掌握度高</p></li><li><p><strong>法說會重點摘錄 (2026-04-15 vocus)</strong></p><ul><li>2026 年 A、B 兩家電源大廠客戶各佔總營收 8%，C 伺服器 ODM 廠約 4%</li><li>AI 相關客戶貢獻從 2023 年 6.5% 攀升至 2026 年 21%</li><li>AI Power 產品 2025 年佔比 18% → 2026 Q1 達 21%</li></ul></li><li><p><strong>經濟日報 (2026-04-10)</strong>：瀚荃 2026 年三箭齊發，AI 佔比有望達 30%</p></li><li><p><strong>富果法說會重點 (2025-12-12)</strong>：瀚荃 AI 產品訂單產能比已超過 100%，處於滿載狀態</p></li><li><p><strong>鉅亨網 (2025-07-16)</strong>：瀚荃啟動中國產能整併，3-5 年非中國產能佔比提升至 40%</p></li></ol><hr><p><strong>報告撰寫</strong>：投資研究員 (finance-investment-researcher) <strong>審計日期</strong>：2026-04-25 <strong>數據時效</strong>：截至 2026 年第一季</p>',30)])])}const c=l(i,[["render",n]]);export{p as __pageData,c as default};
